#include <Wire.h>
#include <Adafruit_MCP4725.h>

extern float lpr_corrosion_rate(float dV,float dI,float area,float B);

Adafruit_MCP4725 dac;
const int INA_PIN=A0,DE_PIN=2;
const float AREA_CM2=10.0f,B_ACTIVE=26.0f,B_PASSIVE=52.0f;
const float CR_ACTIVE_THRESH=0.01f;

// === DAC Bias ===
void dac_init(){Wire.begin();dac.begin(0x60);}
void dac_set_mV(float mV){uint16_t v=(uint16_t)((mV+1000.0f)/2000.0f*4095);dac.setVoltage(v,false);}

// === Current Readback ===
float current_uA_read(){return (analogRead(INA_PIN)-512)*5000.0f/1023.0f;}

// === LPR Scan ===
float lpr_scan(){
  dac_set_mV(0);delay(2000);
  float i0=current_uA_read();
  dac_set_mV(10);delay(500);
  float ip=current_uA_read();
  dac_set_mV(-10);delay(500);
  float im=current_uA_read();
  dac_set_mV(0);
  float dI=(ip-im)/2.0f-i0;
  float B=(abs(dI)>0.1f)?B_ACTIVE:B_PASSIVE;
  return lpr_corrosion_rate(10.0f,abs(dI),AREA_CM2,B);}

// === Modbus RTU Transmit ===
void modbus_init(){Serial.begin(9600);pinMode(DE_PIN,OUTPUT);digitalWrite(DE_PIN,HIGH);}
void modbus_send(float cr,bool active){
  uint16_t cr_enc=(uint16_t)(cr*1000);
  uint8_t frame[]={0x01,0x04,0x00,0x01,0x00,0x02,(uint8_t)(cr_enc>>8),(uint8_t)(cr_enc&0xFF),active?0x01:0x00,0x00};
  Serial.write(frame,10);}

// === Fault Handler ===
bool fault_check(float cr){if(cr<0){Serial.println("FAULT:SENSOR");return true;}return false;}

void setup(){
  dac_init();modbus_init();
  Serial.println("Rebar Corrosion Monitor Ready");
}

void loop(){
  float cr=lpr_scan();
  if(fault_check(cr)){delay(60000);return;}
  bool active=(cr>CR_ACTIVE_THRESH);
  modbus_send(cr,active);
  if(active)Serial.println("ALARM:ACTIVE_CORROSION");
  Serial.print("CR=");Serial.print(cr,4);Serial.println(" mm/yr");
  delay(900000);
}
